// Extrair dados da mensagem da Evolution API
const body = $input.first().json.body || $input.first().json;

// Suporte para formato Evolution API v2
const data = body.data || body;
const event = body.event || '';

// Ignorar mensagens enviadas pelo próprio bot
if (event === 'messages.upsert' && data.key && data.key.fromMe === true) {
  return [];
}

// Ignorar status/stories
if (data.key && data.key.remoteJid && data.key.remoteJid.endsWith('@g.us')) {
  return []; // Ignorar grupos
}
if (data.key && data.key.remoteJid && data.key.remoteJid.endsWith('@broadcast')) {
  return [];
}

const remoteJid = data.key?.remoteJid || '';
const whatsapp = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');
const pushName = data.pushName || '';

let messageType = 'texto';
let messageContent = '';
let audioUrl = '';
let hasUrl = false;
let extractedUrl = '';

// Detectar tipo de mensagem
const msg = data.message || {};

if (msg.conversation) {
  messageContent = msg.conversation;
} else if (msg.extendedTextMessage?.text) {
  messageContent = msg.extendedTextMessage.text;
} else if (msg.audioMessage) {
  messageType = 'audio';
  audioUrl = msg.audioMessage.url || data.mediaUrl || '';
  // Se não tiver URL direta, usar base64
  if (!audioUrl && data.base64) {
    audioUrl = 'base64:' + data.base64;
  }
} else if (msg.imageMessage?.caption) {
  messageContent = msg.imageMessage.caption;
} else if (msg.videoMessage?.caption) {
  messageContent = msg.videoMessage.caption;
} else if (msg.documentMessage) {
  messageContent = '[Documento enviado]';
} else if (msg.stickerMessage) {
  messageContent = '[Sticker]';
} else {
  messageContent = '[Mensagem não suportada]';
}

// Detectar URLs no texto
if (messageType === 'texto' && messageContent) {
  const urlRegex = /(https?:\/\/[^\s]+)|(www\.[^\s]+)|([a-zA-Z0-9-]+\.(com|com\.br|net|org|io|dev|site|online|store|app|tech|digital|design|agency|pro|biz|info)(\.[a-z]{2})?(\/[^\s]*)?)/gi;
  const urls = messageContent.match(urlRegex);
  if (urls && urls.length > 0) {
    hasUrl = true;
    extractedUrl = urls[0];
    if (!extractedUrl.startsWith('http')) {
      extractedUrl = 'https://' + extractedUrl;
    }
  }
}

return [{
  json: {
    whatsapp,
    pushName,
    messageType,
    messageContent,
    audioUrl,
    hasUrl,
    extractedUrl,
    rawEvent: event,
    instanceName: body.instance || '',
    timestamp: new Date().toISOString()
  }
}];

// Unificar mensagem transcrita com texto normal
const items = $input.all();
const item = items[0].json;

let messageContent = '';
let transcricaoAudio = null;

// Verificar se veio da transcrição
if (item.text) {
  messageContent = item.text;
  transcricaoAudio = item.text;
} else {
  messageContent = item.messageContent || '';
  transcricaoAudio = null;
}

// Recuperar dados originais
const originalData = $('Extrair Dados da Mensagem').first().json;

return [{
  json: {
    ...originalData,
    messageContent: messageContent || originalData.messageContent,
    transcricaoAudio,
    processedAt: new Date().toISOString()
  }
}];

// Processar resultados do PageSpeed
const pageSpeed = $input.first().json;
const original = $('Unificar Mensagem').first().json;

let analise = '';

try {
  const cats = pageSpeed.lighthouseResult?.categories || {};
  const perf = Math.round((cats.performance?.score || 0) * 100);
  const access = Math.round((cats.accessibility?.score || 0) * 100);
  const bp = Math.round((cats['best-practices']?.score || 0) * 100);
  const seo = Math.round((cats.seo?.score || 0) * 100);

  const audits = pageSpeed.lighthouseResult?.audits || {};
  const fcp = audits['first-contentful-paint']?.displayValue || 'N/A';
  const lcp = audits['largest-contentful-paint']?.displayValue || 'N/A';
  const cls = audits['cumulative-layout-shift']?.displayValue || 'N/A';
  const speed = audits['speed-index']?.displayValue || 'N/A';
  const mobile = audits['viewport']?.score === 1 ? 'Sim' : 'Não';

  analise = `\n📊 ANÁLISE DO SITE: ${original.extractedUrl}\n`;
  analise += `\n🏆 PONTUAÇÕES GOOGLE PAGESPEED (Mobile):\n`;
  analise += `• Performance: ${perf}/100\n`;
  analise += `• Acessibilidade: ${access}/100\n`;
  analise += `• Boas Práticas: ${bp}/100\n`;
  analise += `• SEO: ${seo}/100\n`;
  analise += `\n⚡ MÉTRICAS DE VELOCIDADE:\n`;
  analise += `• First Contentful Paint: ${fcp}\n`;
  analise += `• Largest Contentful Paint: ${lcp}\n`;
  analise += `• Cumulative Layout Shift: ${cls}\n`;
  analise += `• Speed Index: ${speed}\n`;
  analise += `• Responsivo (Mobile): ${mobile}\n`;

  // Problemas encontrados
  const problems = [];
  if (perf < 50) problems.push('Performance muito baixa');
  if (perf >= 50 && perf < 80) problems.push('Performance pode melhorar');
  if (access < 80) problems.push('Acessibilidade precisa de atenção');
  if (seo < 80) problems.push('SEO precisa ser otimizado');
  if (bp < 80) problems.push('Boas práticas não seguidas');
  if (mobile === 'Não') problems.push('Site NÃO é responsivo');

  if (problems.length > 0) {
    analise += `\n⚠️ PROBLEMAS IDENTIFICADOS:\n`;
    problems.forEach(p => analise += `• ${p}\n`);
  }
} catch(e) {
  analise = `Não foi possível analisar o site ${original.extractedUrl}. Erro: ${e.message}`;
}

return [{
  json: {
    ...original,
    analiseSite: analise,
    temAnaliseSite: true
  }
}];

// Sem URL - passar direto
const original = $('Unificar Mensagem').first().json;
return [{
  json: {
    ...original,
    analiseSite: '',
    temAnaliseSite: false
  }
}];

// Verificar se lead existe e preparar dados
const leadResults = $input.first().json;
const msgData = $('Processar PageSpeed').first()?.json || $('Sem Análise de Site').first()?.json;

// Se não encontrou em nenhum, tentar pegar do último merge
const dados = msgData || $input.first().json;

const leadExists = Array.isArray($input.all()) && $input.first().json && $input.first().json.id;

return [{
  json: {
    ...dados,
    leadExists: leadExists,
    leadId: leadExists ? $input.first().json.id : null,
    leadNome: leadExists ? $input.first().json.nome : dados.pushName,
    leadStatus: leadExists ? $input.first().json.status : 'novo',
    leadCategoria: leadExists ? $input.first().json.categoria : null,
    leadInteresses: leadExists ? $input.first().json.interesses : null,
    leadHistoricoResumo: leadExists ? $input.first().json.historico_resumo : null
  }
}];

// Preparar lead_id para próximos passos
const prevData = $('Verificar Lead').first().json;
let leadId;

try {
  // Veio do Criar Lead
  leadId = $('Criar Lead').first().json.id;
} catch(e) {
  // Veio do Lead Existe (true)
  leadId = prevData.leadId;
}

return [{
  json: {
    ...prevData,
    leadId: leadId || prevData.leadId
  }
}];

// Montar contexto completo para o GPT
const msgData = $('Definir Lead ID').first().json;
const historicoRows = $input.all().map(i => i.json);

// Formatar histórico
let historicoFormatado = '';
if (historicoRows && historicoRows.length > 0 && historicoRows[0].mensagem) {
  const reversed = [...historicoRows].reverse();
  historicoFormatado = reversed.map(h => {
    const tipo = h.tipo === 'recebida' ? '👤 Cliente' : '🤖 Buildesign';
    const data = new Date(h.data_hora).toLocaleString('pt-BR');
    let msg = h.mensagem || '';
    if (h.transcricao_audio) msg += ` [Áudio transcrito: ${h.transcricao_audio}]`;
    return `${tipo} (${data}): ${msg}`;
  }).join('\n');
} else {
  historicoFormatado = 'Primeira interação - sem histórico anterior.';
}

// Mensagem atual
let mensagemAtual = msgData.messageContent || '';
if (msgData.transcricaoAudio) {
  mensagemAtual = `[Áudio transcrito]: ${msgData.transcricaoAudio}`;
}

// Análise de site (se houver)
let contextSite = '';
if (msgData.temAnaliseSite && msgData.analiseSite) {
  contextSite = `\n\n--- ANÁLISE AUTOMÁTICA DO SITE DO CLIENTE ---\n${msgData.analiseSite}\n--- FIM DA ANÁLISE ---`;
}

return [{
  json: {
    ...msgData,
    historicoFormatado,
    mensagemAtual,
    contextSite,
    promptContext: `
INFORMAÇÕES DO LEAD:
- Nome: ${msgData.leadNome || msgData.pushName || 'Desconhecido'}
- WhatsApp: ${msgData.whatsapp}
- Status atual: ${msgData.leadStatus || 'novo'}
- Categoria: ${msgData.leadCategoria || 'Não classificado'}
- Interesses: ${msgData.leadInteresses || 'Não identificados'}
- Resumo do histórico: ${msgData.leadHistoricoResumo || 'Sem resumo anterior'}

HISTÓRICO DAS ÚLTIMAS CONVERSAS:
${historicoFormatado}

MENSAGEM ATUAL DO CLIENTE:
${mensagemAtual}
${contextSite}`
  }
}];

// Processar resposta do GPT
const gptResponse = $input.first().json;
const msgData = $('Montar Contexto GPT').first().json;

let resposta = '';
let categoria = 'MORNO';
let interesses = '';
let resumo = '';
let sugerirReuniao = false;
let intencao = '';

try {
  const content = gptResponse.choices[0].message.content.trim();

  // Tentar parsear JSON
  let parsed;
  try {
    parsed = JSON.parse(content);
  } catch(e) {
    // Tentar extrair JSON de dentro de markdown
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[0]);
    } else {
      parsed = { resposta: content };
    }
  }

  resposta = parsed.resposta || content;
  categoria = parsed.categoria || 'MORNO';
  interesses = parsed.interesses || '';
  resumo = parsed.resumo || '';
  sugerirReuniao = parsed.sugerir_reuniao || false;
  intencao = parsed.intencao || '';
} catch(e) {
  resposta = 'Olá! Obrigado por entrar em contato com a Buildesign. Como posso ajudar você hoje? 😊';
}

return [{
  json: {
    ...msgData,
    respostaGPT: resposta,
    categoria,
    interesses,
    resumo,
    sugerirReuniao,
    intencao
  }
}];
